import{_ as e,W as o,X as p,Y as t}from"./framework-9a5142fa.js";const c={},s=t('<p>作步骤大概如下：</p><p>第一步：</p><p>​ 启动虚拟机，然后确保光标此时已经在虚拟机内了，出现启动倒计时界面时，按键盘上的任意键，进入如下界面：</p><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406102040710.png" alt="在这里插入图片描述"></p><p>​ 在白条选中的这个CentOs Linux上，按下键盘的e键，进入编辑模式：</p><p>第二步：</p><pre><code>在`crashkernel`前面，`ro`(即readonly权限），修改`ro`-&gt;`rw`，另外，加入 `init=/sysroot/bin/sh`\n</code></pre><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406102040070.png" alt="在这里插入图片描述"></p><p>​ 修改完成后，Ctrl+x保存</p><p>​ 然后会进入安全模式：</p><p>​ 输入<code>chroot /sysroot</code>命令，然后<code>passwd</code>命令才可以使用，运行passwd,并按提示修改root密码，输入密码和确认密码后，即可修改成功。</p><p>​ <img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202406102041617.png" alt="image-20240610204147593"></p><p>第三步：</p><p>​ 然后运行命令<code>touch /.autorelabel</code>，使得修改的密码生效，否则修改的密码不起作用。</p><p>​ 接着使用<code>exit</code>命令退出</p><p>​ 然后<code>reboot</code>命令重启虚拟机的Linux服务</p>',16),r=[s];function n(d,i){return o(),p("div",null,r)}const l=e(c,[["render",n],["__file","重置root密码.html.vue"]]);export{l as default};
